const cities = ['New York NY','Los Angeles CA','Chicago IL','Houston TX','Phoenix AZ','Dallas TX','Miami FL','Atlanta GA','Seattle WA','Denver CO'];
const queries = ['architecture firm','residential architect','commercial architect'];
const tasks = [];
for (const c of cities) { for (const q of queries) { tasks.push({city: c.split(' ')[0], state: c.split(' ')[1], query: q, location: c}); } }
return tasks.slice(0, 3);

const results = ($input.first().json.results || []).map(p => ({
  businessName: p.name || '',
  address: p.formatted_address || p.vicinity || '',
  phone: p.formatted_phone_number || '',
  website: p.website || '',
  rating: p.rating || 0,
  totalRatings: p.user_ratings_total || 0,
  placeId: p.place_id || '',
  latitude: p.geometry?.location?.lat || '',
  longitude: p.geometry?.location?.lng || '',
  source: 'GoogleMaps'
}));
return results;

const allBiz = [];
for (const item of $input.all()) {
  if (Array.isArray(item.json)) { allBiz.push(...item.json); }
  else if (item.json.businessName) { allBiz.push(item.json); }
}

const unique = new Map();
for (const biz of allBiz) {
  const key = (biz.website || biz.businessName + '|' + biz.phone).toLowerCase().trim();
  if (!key || key === '|') continue;
  if (!unique.has(key)) {
    unique.set(key, { ...biz, id: 'lead-' + Date.now() + '-' + unique.size, collectedAt: new Date().toISOString() });
  } else {
    const old = unique.get(key);
    if (biz.website && !old.website) old.website = biz.website;
    if (biz.phone && !old.phone) old.phone = biz.phone;
    old.source = (old.source || '') + ';' + biz.source;
  }
}

return Array.from(unique.values());

const newBiz = $input.all().find(i => Array.isArray(i.json))?.json || [];
const existingData = $input.all().find(i => i.json.data)?.json?.data || [];

const existingWebsites = new Set(existingData.map(l => (l.website || '').toLowerCase().trim()).filter(Boolean));

const toAdd = [];
for (const biz of newBiz) {
  const w = (biz.website || '').toLowerCase().trim();
  if (w && existingWebsites.has(w)) continue;
  if (w) existingWebsites.add(w);
  toAdd.push(biz);
}

return { newLeads: toAdd, added: toAdd.length, skipped: newBiz.length - toAdd.length };

const data = $input.first().json;
const leads = data.newLeads || [];

if (leads.length === 0) {
  return { written: 0, message: 'No new leads', success: true };
}

const headers = ['id','businessName','website','email','phone','address','city','state','zip','source','websiteScore','emailValid','socialScore','leadScore','status','createdAt','updatedAt'];

const rows = leads.map(l => ({
  id: l.id || 'lead-' + Date.now(),
  businessName: l.businessName || '',
  website: l.website || '',
  email: l.email || '',
  phone: l.phone || '',
  address: l.address || '',
  city: l.city || '',
  state: l.state || '',
  zip: l.zip || '',
  source: l.source || '',
  websiteScore: '0',
  emailValid: 'pending',
  socialScore: '0',
  leadScore: '0',
  status: 'new',
  createdAt: l.collectedAt || new Date().toISOString(),
  updatedAt: new Date().toISOString()
}));

return { rows, count: rows.length, headers };
